const rows = $('Get row(s) in sheet').all().map(r => r.json);
const hari = new Date().toLocaleDateString('id-ID', {day:'2-digit', month:'long', year:'numeric'});

const HARGA_BELI = 16000;
const HARGA_JUAL = 19000;
const DANA_TABUNGAN = 10000;

let totalTabung = 0, totalOmset = 0;
let totalLunas = 0, totalHutang = 0, totalDP = 0, totalDPUang = 0;
const ringkasan = {};

for (const r of rows) {
  const findVal = (obj, key) => {
    const k = Object.keys(obj).find(k => k.trim() === key);
    return k ? obj[k] : null;
  };
  const jml = parseInt(findVal(r, 'Jumlah Tabung Terjual')) || 0;
  const ukuran = findVal(r, 'Ukuran Tabung') || 'Lain';
  const status = (r['Status Pembayaran'] || 'Lunas').trim();
  const dibayar = parseInt(r['Jumlah Dibayar (Rp)']) || 0;

  if (jml > 0) {
    totalTabung += jml;
    totalOmset += jml * HARGA_JUAL;
    ringkasan[ukuran] = (ringkasan[ukuran] || 0) + jml;

    if (status === 'Lunas') totalLunas += jml * HARGA_JUAL;
    else if (status === 'Hutang') totalHutang += jml * HARGA_JUAL;
    else if (status === 'DP') {
      totalDP += jml * HARGA_JUAL;
      totalDPUang += dibayar;
    }
  }
}

const detail = Object.entries(ringkasan)
  .map(([k,v]) => `  • ${k}: ${v} tabung`).join('\n') || '  • Belum ada penjualan';

const stokNode = $('Get row(s) in sheet1').all();
const findStok = (obj, key) => {
  const k = Object.keys(obj).find(k => k.trim() === key);
  return k ? obj[k] : null;
};
const stokAwal = stokNode.length > 0 ? parseInt(findStok(stokNode[0].json, 'Stok Awal (tabung)')) || 0 : 0;
const sisaStok = stokAwal > 0 ? stokAwal - totalTabung : 'Belum diinput';
const statusStok = stokAwal === 0 ? '⚠️ Stok pagi belum diinput' : sisaStok <= 10 ? '⚠️ MENIPIS' : '✅ Aman';

const modalHari = totalTabung * HARGA_BELI;
const keuntunganKotor = totalTabung * (HARGA_JUAL - HARGA_BELI);
const keuntunganBersih = keuntunganKotor - DANA_TABUNGAN;
const uangDitangan = totalLunas + totalDPUang;
const sisaTagihan = totalHutang + (totalDP - totalDPUang);

const pesan = `📊 LAPORAN HARIAN — ${hari}

🫙 Total terjual: ${totalTabung} tabung
${detail}

📦 Sisa stok: ${typeof sisaStok === 'number' ? sisaStok + ' tabung' : sisaStok} ${statusStok}

💰 Omset hari ini: Rp ${totalOmset.toLocaleString('id-ID')}
✅ Sudah dibayar: Rp ${uangDitangan.toLocaleString('id-ID')}
⏳ Belum dibayar: Rp ${sisaTagihan.toLocaleString('id-ID')}

🏭 Modal: Rp ${modalHari.toLocaleString('id-ID')}
📈 Keuntungan kotor: Rp ${keuntunganKotor.toLocaleString('id-ID')}
🏦 Dana tabungan: Rp ${DANA_TABUNGAN.toLocaleString('id-ID')}
✅ Keuntungan bersih: Rp ${keuntunganBersih.toLocaleString('id-ID')}

_Otomatis dikirim jam 21.00_`;

return [{ json: { pesan } }];
